class Solution {
public:
    int nextBeautifulNumber(int n) {
        for (int i = n + 1; ; i++) {
            string str = to_string(i);
            unordered_map<char, int> count;
            for (char c : str) count[c]++;
            bool isValid = true;
            for (char c : str) {
                if (count[c] != c - '0') {
                    isValid = false;
                    break;
                }
            }
            if (isValid) return i;
        }
    }
};
